-- Seed data for the 10 launch national parks + their attractions and trails.
-- Generated from data/01_parks_content_template.csv.csv, 02_attractions_template.csv.csv, 03_trails_template.csv.csv.
-- Run once in Supabase: Project -> SQL Editor -> New query -> paste -> Run.
--
-- Note: activities/facilities/attraction type/trail difficulty values are inserted
-- verbatim from the CSVs (not normalized against the controlled vocabulary). Values
-- outside the vocab used by src/constants/parks.ts fall back to a generic icon/label
-- in the UI rather than failing -- see CLAUDE.md.

alter table national_parks
  add column if not exists lat double precision,
  add column if not exists lng double precision,
  add column if not exists tel_number text;

with inserted_parks as (
  insert into national_parks
    (name_th, name_en, region, province, entrance_fee_adult, open_hours, website_url,
     activities, best_season, facilities, established_year, highlights, description,
     image_url, lat, lng, tel_number)
  values
  ('อุทยานแห่งชาติเขาใหญ่', 'Khao Yai', 'อีสาน', 'นครราชสีมา', 40, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=640', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'ชมพรรณไม้', 'ดูนก', 'ส่องสัตว์', 'ดูดาว', 'ปั่นจักรยาน', 'ล่องแก่ง', 'ตั้งแคมป์พักแรม']::text[], 'ตลอดปี', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1962, NULL, 'ผืนป่าใจกลางประเทศที่เดินป่าเจอช้างป่าได้จริง เป็นส่วนหนึ่งของมรดกโลกดงพญาเย็น-เขาใหญ่ ใกล้กรุงเทพฯ ที่สุดในบรรดาผืนป่าใหญ่', NULL, 14.43489488, 101.375837, '08860926529'),
  ('อุทยานแห่งชาติภูกระดึง', 'Phu Kradueng', 'อีสาน', 'เลย', 40, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=945', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'ชมพรรณไม้', 'ดูนก', 'ส่องสัตว์', 'ปั่นจักรยาน', 'ตั้งแคมป์พักแรม']::text[], 'ต.ค - พ.ค', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1962, NULL, 'ภูเขาหินทรายยอดตัดที่ต้องเดินขึ้นเองราว 9 กม. กว่าจะถึงลานสน อากาศเย็นตลอดปีและวิวพระอาทิตย์ขึ้นที่ผาหล่มสัก คุ้มค่าทุกก้าวที่เดิน', NULL, 16.8712317, 101.845769, '0842810833'),
  ('อุทยานแห่งชาติดอยอินทนนท์', 'Doi Inthanon', 'เหนือ', 'เชียงใหม่', 60, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=915', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'ชมพรรณไม้', 'ดูนก', 'ส่องสัตว์', 'ดููดาว', 'ปั่นจักรยาน', 'ชมประวัติศาสตร์/วัฒนธรรม', 'ตั้งแคมป์พักแรม']::text[], 'พ.ย - ก.พ', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1972, NULL, 'จุดสูงสุดของประเทศไทย อากาศหนาวเย็นตลอดปีจนได้ฉายาหลังคาเมืองไทย ทุ่งดอกกุหลาบพันปีและทะเลหมอกยามเช้าที่กิ่วแม่ปานสวยจนต้องแวะ', NULL, 18.5356262, 98.5221239, '0853286729'),
  ('อุทยานแห่งชาติแก่งกระจาน', 'Kaeng Krachan', 'ตะวันตก', 'เพชรบุรี', 60, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=642', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'ชมพรรณไม้', 'ดูนก', 'ดูดาว', 'ตั้งแคมป์พักแรม']::text[], 'ตลอดปี', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1981, NULL, 'อุทยานที่มีพื้นที่ใหญ่ที่สุดในไทย ป่าดิบชื้นผืนใหญ่ที่นักดูนกทั่วโลกต้องมาเยือน กางเต็นท์ริมอ่างเก็บน้ำท่ามกลางหมอกยามเช้า', NULL, 12.8850041, 99.6317361, '0832772311'),
  ('อุทยานแห่งชาติเขาสก', 'Khao Sok', 'ใต้', 'สุราษฎร์ธานี', 40, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=1019', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'เที่ยวถ้ำ', 'ชมพรรณไม้', 'ดูนก', 'ส่องสัตว์', 'ดูดาว', 'ปั่นจักรยาน', 'พายเรือ', 'ตั้งแคมป์พักแรม']::text[], 'ตลอดปี', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1980, NULL, 'ป่าฝนที่เก่าแก่กว่าแอมะซอน ทะเลสาบเชี่ยวหลานเขาหินปูนตระการตา ล่องแพนอนกลางน้ำท่ามกลางเขาหินปูนที่โผล่พ้นผืนน้ำ', NULL, 8.9777134, 98.6381879, '0877395155'),
  ('อุทยานแห่งชาติหมู่เกาะสิมิลัน', 'Mu Ko Similan', 'ใต้', 'พังงา', 100, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=865', ARRAY['เดินป่า', 'ชมพรรณไม้', 'ดูนก', 'ปั่นจักรยาน', 'พายเรือ', 'ดำผิวน้ำ', 'ดำน้ำลึก']::text[], 'ต.ค - พ.ค', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1982, NULL, 'หมู่เกาะน้ำใสระดับโลก หาดทรายขาวละเอียด แนวปะการังสมบูรณ์ จุดดำน้ำระดับต้นๆ ของโลก เปิดเฉพาะฤดูกาล ต.ค.–พ.ค.', NULL, 8.6573948, 97.6488877, '076453272'),
  ('อุทยานแห่งชาติเขาแหลมหญ้า-หมู่เกาะเสม็ด', 'Khao Laem Ya - Mu Ko Samet', 'ตะวันออก', 'ระยอง', 40, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=990', ARRAY['เดินป่า', 'ชมพรรณไม้', 'ดำน้ำ', 'ตั้งแคมป์พักแรม']::text[], 'ตลอดปี', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1981, NULL, 'เกาะทะเลใกล้กรุงเทพฯ ที่สุด นั่งเรือไม่ถึงชั่วโมงก็ถึงหาดทรายขาวน้ำใส เหมาะสำหรับทริปสั้นๆ วันหยุดสุดสัปดาห์', NULL, 12.5914129, 101.4182013, '0838653034'),
  ('อุทยานแห่งชาติดอยผ้าห่มปก', 'Doi Pha Hom Pok', 'เหนือ', 'เชียงใหม่', 60, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=908', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'เที่ยวถ้ำ', 'ชมพรรณไม้', 'ดูนก', 'ดูดาว', 'อาบน้ำแร่', 'ตั้งแคมป์พักแรม']::text[], 'ต.ค - มี.ค', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 2000, NULL, 'ยอดเขาสูงอันดับสองของไทย อากาศหนาวจัดจนน้ำค้างแข็งตัวในบางปี มีทั้งดอกไม้เมืองหนาวและบ่อน้ำพุร้อนฝางให้แช่คลายหนาว', NULL, 19.9966004, 99.144325, '08844834689'),
  ('อุทยานแห่งชาติเอราวัณ', 'Erawan', 'ตะวันตก', 'กาญจนบุรี', 60, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=643', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'เที่ยวถ้ำ', 'ชมพรรณไม้', 'ดูนก', 'ตั้งแคมป์พักแรม']::text[], 'ตลอดปี', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1975, NULL, 'น้ำตกเจ็ดชั้นที่มีชื่อเสียงที่สุดในไทย น้ำสีเขียวมรกตใสจนเห็นปลาพลวงว่ายวน เดินขึ้นครบทั้ง 7 ชั้นได้ในวันเดียว', NULL, 14.3754962, 99.1439623, '0834574222'),
  ('อุทยานแห่งชาติผาแต้ม', 'Pha Taem', 'อีสาน', 'อุบลราชธานี', 40, '08:00-16:00', 'https://portal.dnp.go.th/Content/nationalpark?contentId=957', ARRAY['เดินป่า', 'เที่ยวน้ำตก', 'เที่ยวถ้ำ', 'ชมพรรณไม้', 'ดูนก', 'ดูดาว', 'ปั่นจักรยาน', 'ตั้งแคมป์พักแรม']::text[], 'ตลอดปี', ARRAY['ห้องน้ำ', 'ที่จอดรถ', 'ร้านค้า', 'จุดกางเต็นท์', 'บ้านพัก', 'ศูนย์บริการนักท่องเที่ยว', 'ร้านอาหาร', 'จุดชาร์จไฟ']::text[], 1992, NULL, 'ผาหินริมแม่น้ำโขงที่เห็นพระอาทิตย์ขึ้นก่อนใครในสยาม ภาพเขียนสีก่อนประวัติศาสตร์อายุกว่า 3,000 ปีเรียงรายตามหน้าผา', NULL, 15.3987457, 105.5075256, '045252581')
  returning id, name_th
),
inserted_attractions as (
  insert into attractions (park_id, attraction_name, type, description, lat, lng, image_url)
  select ip.id, v.attraction_name, v.type, v.description, v.lat, v.lng, v.image_url
  from (values
  ('อุทยานแห่งชาติเขาใหญ่', 'น้ำตกเหวสุวัต', 'น้ำตก', 'เป็นน้ำตกแห่งแรกของลำห้วยลำตะคองที่ไหลผ่านหน้าผาหินทรายโค้งสูงประมาณ 20 เมตร ลงสู่แอ่งน้ำด้านล่างที่มีความสวยงามเป็นอย่างมาก โดยเฉพาะในช่วงฤดูฝนจะมีน้ำมากและกระแสน้ำแรง ส่วนในช่วงหน้าแล้งปริมาณน้ำค่อนข้างน้อยจนเห็นน้ำตกเป็นสายน้ำเล็กๆ จนเห็นโพรงถ้ำหลังน้ำตก', 14.43562601, 101.4141585, NULL),
  ('อุทยานแห่งชาติเขาใหญ่', 'หอดูสัตว์หนองผักชี', 'จุดดูสัตว์', 'หอดูสัตว์หนองผักชี สามารถมองเห็นทิวทัศน์ได้โดยรอบ ในบางเวลาจะเห็นสัตว์มากินดินที่โป่งเทียม และกินน้ำที่แหล่งน้ำ การเดินทางมาที่หอดูสัตว์หนองผักชี ให้จอดรถที่บริเวณกิโลเมตร 35 ถนนธนะรัชต์ แล้วเดินเข้ามาระหว่างทางจะเป็นป่าหญ้า ระยะทางประมาณ 1 กิโลเมตร', 14.45410376, 101.3602631, NULL),
  ('อุทยานแห่งชาติเขาใหญ่', 'ผาเดียวดาย', 'จุดชมวิว', 'เป็นจุดชมทิวทัศน์ที่สวยงามน่าชม มีลักษณะคล้ายผานกเค้าที่ภูกระดึง เป็นจุดชมวิวซึ่งเป็นลานหินยื่นออกมาจากหน้าผา ขนาดพื้นที่ประมาณ 15 ตารางเมตร มุมมองกว้างจะมองเห็นภูเขาร่มขวางอยู่เป็นแนวยาว และป่าดงดิบหนาทึบ จนถึงทุ่งงูเหลือม และเขาสมอปูน ตอนเช้าตรู่จะเห็นดวงอาทิตย์ขึ้นยามเช้าเป็นดวงกลมสีแดงเหนือสันเขาร่มที่สวยงาม', 14.36781546, 101.4073345, NULL),
  ('อุทยานแห่งชาติภูกระดึง', 'ผานกแอ่น', 'จุดชมวิว', 'เป็นลานหินเล็กๆ มีสนขึ้นโดดเด่นริมหน้าผาต้นหนึ่ง เป็นจุดชมพระอาทิตย์ขึ้นที่งดงามยิ่ง อากาศสดชื่นเย็นสบาย มองเห็นทิวทัศน์เบื้องล่างซึ่งเป็นท้องทุ่งและเทือกเขา เห็นผานกเค้าได้ชัดเจน ริมทางเดินใกล้ผานกแอ่นเป็นสวนหินมีดอกกุหลาบป่าขึ้นอยู่เป็นดงใหญ่ จะบานสะพรั่งเต็มต้นในเดือนมีนาคม-เมษายน ผู้ที่ไปชมประอาทิตย์ขึ้นที่ผานกแอ่น ควรเตรียมไฟฉายสำหรับใช้ส่องทางไปด้วย', 16.89348772, 101.8001705, NULL),
  ('อุทยานแห่งชาติภูกระดึง', 'ผาหล่มสัก', 'จุดชมวิว', 'เป็นลานหินกว้างและมีสนต้นหนึ่งขึ้นชิดริมผาใกล้กับชะง่อนหินที่ยื่นออกไปในอากาศทางทิศใต้ บริเวณผาหล่มสักนี้มองเห็นทิวทัศน์ของเทือกเขาสลับซับซ้อนในเขตจังหวัดเพชรบูรณ์ และเป็นจุดหนึ่งที่จะชมพระอาทิตย์ตกได้อย่างชัดเจนและงดงามมาก ผู้ที่ไปชมประอาทิตย์ตกที่ผาหล่มสัก ควรเตรียมเสื้อกันหนาวและไฟฉายสำหรับใช้ส่องทางเวลาเดินกลับที่พัก ซึ่งโดยทั่วไปจะใช้เวลา 2-3 ชั่วโมง', 16.8601084, 101.7254585, NULL),
  ('อุทยานแห่งชาติภูกระดึง', 'น้ำตกถ้ำใหญ่', 'น้ำตก', 'ในเส้นทางถ้ำใหญ่นี้มีทางเดินบางช่วงที่เลียบข้างลำห้วยเล็กๆ มีต้นเมเปิ้ลอยู่เป็นระยะๆ หากช่วงต้นมกราคม เส้นทางนี้จะแดงฉานด้วยใบเมเปิ้ลที่ร่วงหล่นเกลื่อนพื้นป่า ความสวยงามของน้ำตกถ้ำใหญ่จะแปลกตาด้วยโขดหินมหึมาวางทับซ้อนไม่เป็นระเบียบ ลำธารนี้ขนาบข้างด้วยต้นเมเปิ้ล ยามเมเปิ้ลแดงล่วงหล่น ขัดสีให้ลำธารหินเขียวสวยงามมีสีสันและมีชีวิตชีวาขึ้นมามากนัก', 16.88680566, 101.7791963, NULL),
  ('อุทยานแห่งชาติดอยอินทนนท์', 'กิ่วแม่ปาน', 'เส้นทางศึกษาธรรมชาติ', 'เป็นเส้นทางเดินศึกษาธรรมชาติระยะสั้น เป็นวงรอบระยะทางประมาณ 3 กิโลเมตร  สามารถวนรอบไปกลับในวันเดียว ตามหนทางจะผ่านไปสู่ป่าดงดิบริมธารน้ำ ขึ้นเนินผ่านป่าที่ห้อยระย้าด้วยมอส ฝอยลม ในยามหน้าฝนจะถูกปกคลุมด้วยหมอกขาวและอากาศที่หนาวเย็น สุดปลายทางที่ทุ่งหญ้าบนเนินที่ดารดาษด้วยดอกไม้ตามพื้น', 18.55606404, 98.4825218, NULL),
  ('อุทยานแห่งชาติดอยอินทนนท์', 'น้ำตกผาดอกเสี้ยว', 'น้ำตก', 'เป็นน้ำตกขนาดใหญ่ที่งดงาม ซ่อนตัวอยู่ภายใต้ความสมบูรณ์ของผืนป่า ตั้งชื่อตามชื่อต้นเสี้ยวซึ่งเป็นไม้เด่นบริเวณนั้น มีทั้งหมด 10 ชั้น โดยชั้นที่ชมได้สะดวกคือ ชั้นที่ 6-10 การเดินทางจะต้องเดินเท้าจากที่ทำการอุทยานแห่งชาติประมาณ 1 กิโลเมตร', 18.53822588, 98.53581259, NULL),
  ('อุทยานแห่งชาติดอยอินทนนท์', 'ยอดดอยอินทนนท์', 'ยอดเขา', 'เป็นยอดเขาสูงสุดของประเทศ เป็นดินแดนที่มีสภาพป่าดงดิบเขาระดับสูงที่ยังมีความอุดมสมบูรณ์ มีลักษณะของพันธุ์ไม้เขตอบอุ่น ผสมกับพันธุ์ไม้เขตร้อนที่ยังคงมีพรรณไม้ในสกุลต่างๆ ให้ได้พบเห็นและสิ่งหนึ่งที่จะรู้สึกความแตกต่างระหว่างยอดดอยอินทนนท์กับพื้นที่เชิงดอยก็คืออุณหภูมิความหนาวเย็นที่แตกต่างกันมาก  เหตุที่เกิดปรากฏการณ์เช่น ก็เพราะมีองค์ประกอบหลายอย่าง ความสูงของพื้นที่ก็เป็นตัวกำหนดที่ค่อนข้างเด่นชัด เนื่องจากความสูงที่เพิ่มขึ้น จะทำให้อุณหภูมิลดลง ความสูงเพิ่มขึ้นทุกๆ 100 เมตร จะทำให้อุณหภูมิลดลงโดยเฉลี่ยประมาณ 0.1 องศาเซลเซียส โดยทั่วไปแล้วจะมีสภาพที่ชุ่มชื้นและหนาวเย็นตลอดปี โดยเฉพาะอย่างยิ่งบริเวณยอดดอยอินทนนท์', 18.58812939, 98.48714031, NULL),
  ('อุทยานแห่งชาติแก่งกระจาน', 'เขาพะเนินทุ่ง', 'ยอดเขา', 'มีลักษณะเป็นทุ่งหญ้าและป่าดิบ อากาศหนาวเย็นตลอดปี ประกอบด้วยทิวทัศน์ที่งดงามทั้งยามปกติและยามมีทะเลหมอกใในช่วงปลายฤดูฝนและต้นฤดูหนาวที่งดงามที่สุดแห่งหนึ่ง ซึ่งเหมาะแก่การพักแรม โดยอยู่ห่างจากที่ทำการอุทยานแห่งชาติ 50 กิโลเมตร บนยอดเขาปกคลุมด้วยทุ่งหญ้าและไม้ต้นเล็กๆ', 12.82544694, 99.36355484, NULL),
  ('อุทยานแห่งชาติแก่งกระจาน', 'น้ำตกผาน้ำหยด', 'น้ำตก', 'มีเอกลักษณ์ที่แปลกตา งดงามซึ่งเกิดจากการสะสมของหินปูนจนมีความคล้ายร่ม เป็นจำนวน 3 ชั้น สูงราว 35 เมตร กว้าง 15 เมตรทำให้มีความแตกต่างจากน้ำตกอื่นๆ เมื่อมีน้ำตกไหลลง เกิดความสวยงามเป็นลักษณะคล้ายร่มซ้อนกันหลายๆ ชั้น ด้านล่างของน้ำตกจะมีสระน้ำสีมรกต', 12.70341445, 99.63338866, NULL),
  ('อุทยานแห่งชาติแก่งกระจาน', 'อ่างเก็บน้ำแก่งกระจาน', 'แหล่งน้ำ', 'มีเนื้อที่ประมาณ 46.5 ตารางกิโลเมตร เกิดจากการสร้างเขื่อนดินปิด 3 ช่องทางระหว่างหุบเขา ทำให้น้ำเอ่อล้นท่วมแก่งน้ำเดิม เป็นพื้นน้ำอาณาเขตกว้างขวางจากยอดเขาเนินเขาหลากเป็นเกาะโผล่พ้นน้ำถึง 30-40 เกาะ ก่อให้เกิดทิวทัศน์งดงามยิ่งเหมาะสำหรับการนั่งเรือชมทัศนียภาพและชมพระอาทิตย์ตกยามเย็นที่สันเขาตะนาวศรี', 12.88495196, 99.63170314, NULL),
  ('อุทยานแห่งชาติเขาสก', 'อ่างเก็บน้ำเหนือเขื่อนรัชชประภา', 'แหล่งน้ำ', 'เป็นเขื่อนสำหรับผลิตกระแสไฟฟ้า เป็นเขื่อนอเนกประสงค์ที่สร้างปิดกั้นคลองพระแสง ตัวเขื่อนเป็นหินทิ้งแกนดินเหนียว สูง 95 เมตร ยาว 700 เมตร ระดับสันเขื่อนสูง 100 เมตร อ่างเก็บน้ำมีเกาะมากกว่า 100 เกาะ สมารถล่องเรือชมทัศนียภาพที่สวยงามมาก โดยเฉพาะบริเวณช่องแคบเขากาเลาะบนสันเขื่อนรัชชประภายังเป็นจุดชมทิวทัศน์ที่งดงามของอ่างเก็บน้ำ โดยเฉพาะยามดวงอาทิตย์ตก', 8.97405906, 98.81134761, NULL),
  ('อุทยานแห่งชาติเขาสก', 'ถ้ำน้ำทะลุ', 'ถ้ำ', 'ปากถ้ำกว้างใหญ่ถึง 10 - 50 เมตร ภายในกว้างขวางมีลำธารไหลผ่านตลอดความยาว 500 เมตร ภายในถ้ำมีหินงอกหินย้อย รวมทั้งโขดหินที่เกิดจากการกัดเซาะของสายน้ำจนมีรูปทรงแปลกตา', 8.993704937, 98.60835275, NULL),
  ('อุทยานแห่งชาติเขาสก', 'น้ำตกแม่ยาย', 'น้ำตก', 'เป็นน้ำตกเพียงแห่งเดียวภายในอุทยานแห่งชาติที่รถยนต์ไปถึงได้ อยู่ริมทางหลวงหมายเลข 401 (สุราษฎร์ธานี - ตะกั่วป่า) ตรงกิโลเมตร 113 เป็นน้ำตกชั้นเดียว สูงประมาณ 30 เมตร สวยงามมาก โดยเฉพาะฤดูฝนน้ำจะเต็มหน้าผาที่สูงชันกระจัดกระจายแตกฟองขาวโพลน', 8.883605995, 98.49959052, NULL),
  ('อุทยานแห่งชาติหมู่เกาะสิมิลัน', 'เกาะสิมิลัน (เกาะแปด)', 'เกาะ', 'เป็นเกาะขนาดใหญ่ที่สุดของอุทยานแห่งชาติหมู่เกาะสิมิลัน และเป็นเกาะเดียวที่มีลำธารขนาดเล็กไหลรินตลอดทั้งปี บนยอดสูงสุดของเกาะทางด้านทิศตะวันตกมีกระโจมไฟ ซึ่งเป็นสัญญาณในการเดินเรือตั้งอยู่ ด้านตะวันออกเป็นชายฝั่งยาว มีแนวปะการังขนานกับชายฝั่งจนถึงหัวเกาะด้านตะวันตกเป็นหน้าผาสูง มีกองหินใต้น้ำบางแห่งจนถึงด้านตะวันตกเฉียงเหนือ เป็นอ่าวใหญ่มีลักษณะคล้ายรูปเกือก เรียกว่า อ่าวกือกม้าหรืออ่าวหินเรือใบ', 8.666158773, 97.64881731, NULL),
  ('อุทยานแห่งชาติหมู่เกาะสิมิลัน', 'เกาะเมียง (เกาะสี่)', 'เกาะ', 'เป็นเกาะขนาดใหญ่ ตั้งอยู่กึ่งกลางหมู่เกาะสิมิลัน มีที่ตั้งของหน่วยพิทักษ์อุทยานฯ ที่ สล.1(เกาะเมียง) มีพื้นที่รองจากเกาะสิมิลัน บนเกาะสี่ มี 2 หาด และมีจุดชมวิว', 8.570831778, 97.63708092, NULL),
  ('อุทยานแห่งชาติหมู่เกาะสิมิลัน', 'เกาะตาชัย', 'เกาะ', 'ตั้งอยู่บริเวณเหนือสุดและไกลสุดของหมู่เกาะสิมิลัน เป็นทางผ่านของเส้นทางเดินเรือจากหมู่เกาะสิมิลันไปเกาะสุรินทร์ ป็นอีกเกาะหนึ่งทีมีหาดทรายสวยงาม ส่วนใต้น้ำมีจุดดำน้ำลึกหลายแห่ง ใกล้ชายฝั่งเป็นกอหินใต้น้ำ สามารถพบกระเบนราหูได้ ถัดออกไปเป็นกองหินอีกแห่งหนึ่งที่จะพบปะการังอ่อนและกัลปังหาอยู่ทั่วไป และมีสัตว์น้ำมากมาย', 9.069035907, 97.81072956, NULL),
  ('อุทยานแห่งชาติเขาแหลมหญ้า-หมู่เกาะเสม็ด', 'เขาแหลมหญ้า', 'จุดชมวิว', 'เป็นอ่าวโค้งคล้ายพระจันทร์ครึ่งดวง หาดทรายขาวสะอาดยาวประมาณ 500 เมตร บริเวณหน้าผาด้านหลังอ่าววงเดือนยังเป็นจุดชมพระอาทิตย์ตกที่สวยงามอีกด้วย เขาแหลมหญ้า อยู่เลยบ้านก้นอ่าวไปเล็กน้อย ตามถนนเลียบชายหาดเป็นเนินเขาเตี้ย ๆ ริมทะเล มีเนื้อที่ประมาณ 680 ไร่ บางส่วนเป็นแหลมยื่นออกไปในทะเล ปกคลุมด้วยป่าละเมาะ มีจุดชมวิวที่สามารถมองเห็นหาดแม่รำพึง เกาะเสม็ด และยังเป็นจุดชมพระอาทิตย์ตกด้วย', 12.58369583, 101.4182945, NULL),
  ('อุทยานแห่งชาติเขาแหลมหญ้า-หมู่เกาะเสม็ด', 'หาดแม่รำพึง', 'หาด', 'เป็นหาดที่มีชื่อเสียงของระยอง มีนักท่องเที่ยวมาเที่ยวเป็นประจำ เพราะเป็นหาดที่มีวิวทิวทัศน์สวยงาม มีแนวทิวสนร่มรื่นตลอดแนวหาด ทรายละเอียดนุ่มเท้า หาดมีความลาดชันน้อย และเรียบเป็นแนวทอดยาว 12 กิโลเมตร นักท่องเที่ยวนิยมมานั่งเล่นนอนเล่นพักผ่อน ลงเล่นน้ำทะเล และปิคนิคกันบริเวณชายหาด บริเวณนี้มีร้านอาหารร้านค้าให้บริการอยู่หลายแห่งด้วย จึงเป็นหาดที่ค่อนข้างคึกคักตลอดแทบทั้งปี', 12.61093709, 101.3852399, NULL),
  ('อุทยานแห่งชาติเขาแหลมหญ้า-หมู่เกาะเสม็ด', 'หาดทรายแก้ว', 'หาด', 'เป็นหาดทรายที่สวยที่สุดของเกาะเป็นหาดที่นักท่องเที่ยวทั้งหลายมุ่งหน้ามาชมและเล่นน้ํา เพราะเป็นหาดที่มีทรายขาวสะอาด และละเอียดมาก หาดกว้าง 25-30 เมตร ยาวประมาณ 780 เมตร ราบเรียบปราศจากโขดหินใด ๆ', 12.56793931, 101.4668265, NULL),
  ('อุทยานแห่งชาติดอยผ้าห่มปก', 'น้ำพุร้อนฝาง', 'น้ำพุร้อน', 'เป็นบ่อน้ำร้อนธรรมชาติเกิดจากความร้อนใต้ดิน มีไอร้อนคุกรุ่นอยู่ตลอดเวลา อุณหภูมิของน้ำประมาณ 50 - 87 องศาเซสเซียส', 19.96605216, 99.15422008, NULL),
  ('อุทยานแห่งชาติดอยผ้าห่มปก', 'น้ำตกตาดหมอก', 'น้ำตก', 'ลักษณะที่น้ำตกลงมาเหมือนใยแก้ว ละอองน้ำกระจายอยู่ทั่วแผ่นผาคล้ายหมอก มีน้ำไหลตลอดทั้งปี', 18.96358244, 98.85600624, NULL),
  ('อุทยานแห่งชาติดอยผ้าห่มปก', 'ดอยผ้าห่มปก', 'ยอดเขา', 'เป็นดอยที่สูงอันดับ 2 ของประเทศไทย ด้วยความสูงประมาณ 2,285 เมตรจากระดับน้ำทะเลปานกลาง บนยอดดอยสูงสุดเป็นทุ่งโล่งอันเกิดจากสภาพธรณีวิทยาที่มีชั้นดินตื้น จากยอดดอยจะเห็นทิวทัศน์ที่สวยงาม เช่น ทะเลหมอก และถนนบนสันเขา ขนานกับชายแดนไทย-พม่า ซึ่งถือเป็นถนนที่สร้างขึ้นเพื่อความมั่นคงระหว่างประเทศ', 20.04533309, 99.14539154, NULL),
  ('อุทยานแห่งชาติเอราวัณ', 'น้ำตกเอราวัณ', 'น้ำตก', 'เป็นน้ำตกหินปูน ที่มีความสวยงาม และมีชื่อเสียงแห่งหนึ่งของจังหวัดกาญจนบุรี มีระยะทางยาวประมาณ 2,200 เมตร แบ่งออกเป็นชั้นๆ ได้ 7 ชั้นด้วยกัน ซึ่งแต่ละชั้นมีความสวยงามแตกต่างกันไป และมีชื่อของแต่ละชั้นดังนี้ ชั้นที่ 1 ไหลคืนรัง ชั้นที่ 2 วังมัจฉา ชั้นที่ 3 ผาน้ำตก ชั้นที่ 4 อกนางผีเสื้อ ชั้นที่ 5 เบื่อไม่ลง ชั้นที่ 6 ดงพฤกษา และชั้นที่ 7 ภูผาเอราวัณ ซึ่งเป็นชั้นบนสุดเมื่อน้ำตกไหลบ่าจะมีลักษณะคล้ายช้างสามเศียรหรือที่เรียกว่า "ช้างเอราวัณ" จึงเป็นที่มาของ "อุทยานแห่งชาติเอราวัณ" และน้ำในลำธารเปล่งประกายเป็นสีเขียวมรกตด้วย', 14.36052574, 99.14104898, NULL),
  ('อุทยานแห่งชาติเอราวัณ', 'ถ้ำพระธาตุ', 'ถ้ำ', 'เป็นถ้ำมืดขนาดใหญ่พื้นถ้ำเรียบ มีความยาวประมาณ 200 เมตร มีหินงอกและหินย้อยรูปร่างสวยงามแปลกตา จุดเด่นของถ้ำพระธาตุคือ หินส่วนใหญ่จะโปร่งแสง และมีหินทรายรูปร่างคล้ายพระธาตุ นอกจากนี้ยังมีเสาเอก เสาโท อยู่ภายในถ้ำอีกด้วย ภายในถ้ำแบ่งเป็น 5 ห้อง ได้แก่ กบจำศีล ท้องฟ้าจำลอง เสาเอก ม่านลิเก และระฆัง อากาศภายในถ้ำโปร่งสบาย', 14.39784844, 99.08260119, NULL),
  ('อุทยานแห่งชาติเอราวัณ', 'ถ้ำวังบาดาล', 'ถ้ำ', 'ลักษณะของถ้ำวังบาดาลเป็นถ้ำหินปูนขนาดใหญ่ ปากทางเข้าเป็นห้องเล็กๆ มีหลายห้อง ห้องชั้นล่างมีน้ำไหลผ่านและมีสัตว์น้ำอาศัยอยู่ด้วย นอกจากนี้แต่ละห้องยังมีหินงอกหินย้อย เช่น ห้องม่านพระอินทร์ จะมีลักษณะหินย้อยลงมาคล้ายกับม่าน ห้องเข็มนารายณ์ มีลักษณะคล้ายเข็มแท่งใหญ่ซึ่งความวิจิตรงดงาม', 14.24275376, 99.06299968, NULL),
  ('อุทยานแห่งชาติผาแต้ม', 'จุดชมทิวทัศน์ผาแต้ม', 'จุดชมวิว', 'เป็นจุดชมวิวอีกจุดหนึ่งที่สามารถชมพระอาทิตย์ขึ้นในตอนเช้าได้สวยงามอีกจุดหนึ่งที่สามรถเดินทางเข้าถึงได้ง่าย ด้านล่างหน้าผาสามารถมองเห็นแม่น้ำโขงไหลผ่าน ซึ่งอุทยานแห่งชาติผาแต้ม มีแนวเขตติดกับแม่น้ำโขงยาวถึง 63 เมตร จุดนี้สามารถมองเห็นเทือกเขาของสาธารณรัฐประชาธิปไตยประชาชนลาว แขวงจำปาสัก ด้านล่างยังเห็นพื้นที่ทำการเกษตรของ 3 หมู่บ้าน คือ บ้านกุ่ม บ้านตามุย บ้านท่าล้ง ด้านล่างจุดชมวิวเป็นที่ตั้งของภาพเขียนสี ยาวไปตามหน้าผา', 15.39880759, 105.5076809, NULL),
  ('อุทยานแห่งชาติผาแต้ม', 'ผาชะนะได', 'จุดชมวิว', 'เป็นอีกแหล่งท่องเที่ยวแห่งหนึ่งอยู่ในเขตอุทยานแห่งชาติผาแต้มที่นักท่องเที่ยวให้ความสนใจไปเที่ยวเป็นจำนวนมาก ถือเป็นหน้าผาที่เห็นพระอาทิตย์ขึ้นก่อนใครในสยาม อีกทั้งกรมอุตุนิยมวิทยาใช้เป็นจุดที่ใช้ในการบอกเวลาดวงอาทิตย์ขึ้นนั้นเอง บริเวณผาชะนะได นอกจากจะเห็นแนวแม่น้ำโขงที่ทอดยาวจากเหนือลงใต้แล้ว ยังได้เห็นความอุดมสมบูรณ์ของผืนป่าเขียวขจีกว้างสุดลูกหูลูกตา  ในช่วงปลายฝนต้นหนาวจะในตอนเช้าจะได้เห็นสายธารของหมอกที่ไหลผ่านด้านหน้าผาด้านหลังเป็นเทือกเขาของสาธารณรัฐประชาธิปไตยประชาชนลาวสูงต่ำสลับกันไปผาชะนะไดอยู่ในเขตพื้นที่ป่าดงนาทาม', 15.62103729, 105.6173987, NULL),
  ('อุทยานแห่งชาติผาแต้ม', 'ภาพเขียนสีก่อนประวัติศาสตร์ผาแต้ม', 'แหล่งโบราณคดี', 'เป็นจุดชมภาพเขียนสีที่มีความยาวมากที่สุดเท่าที่พบมาในประเทศไทย มีความยาว 180 เมตร สามารถแบ่งรูปออกได้เป็น 5 ประเภท คือ ภาพคน ภาพผามือ ภาพสัตว์ ภาพวัตถุ และภาพรูปทรงเลขาคณิต ส่วนใหญ่เขียนด้วยสีแดง โดยใช้การแร่ฮีเมไทต์ หรืออาจเป็นเครื่องปั้นดินเผา แล้วมาป่นเป็นผงผสมไข่ขาว นำมันพืช หรือยางไม้ อย่างใดอย่างหนึ่ง ภาพเขียนที่เป็นภาพสัตว์สัดส่วนที่ใหญ่ราวกับขนาดจริง ได้แก่ ช้าง ปลาบึก เต่า ตะพาบน้ำ เป็นต้น', 15.39951061, 105.5122027, NULL)
  ) as v(park_name_th, attraction_name, type, description, lat, lng, image_url)
  join inserted_parks ip on ip.name_th = v.park_name_th
  returning id
)
insert into trails (park_id, trail_name, description, difficulty, distance_km, duration)
select ip.id, v.trail_name, v.description, v.difficulty, v.distance_km, v.duration
from (values
  ('อุทยานแห่งชาติเขาใหญ่', '200 ปี ความสัมพันธ์ไทย-สหรัฐอเมริกา', 'เส้นทางใหม่ล่าสุดของอุทยานเพื่อฉลองความสัมพันธ์อันยาวนานของทั้งสองประเทศ ซึ่งนอกจากเส้นทางจะปรากฏร่องรอยความสัมพันธ์ในประวัติศาสตร์ร่วมกันแล้ว การจัดทำเส้นทางยังใช้มาตรฐานของอุทยานแห่งชาติของสหรัฐอเมริกาภายใต้โครงการอุทยานพี่อุทยานน้องด้วย', 'ง่าย', 2, '1.5 ชั่วโมง'),
  ('อุทยานแห่งชาติเขาใหญ่', 'ศูนย์บริการนักท่องเที่ยว - น้ำตกกองแก้ว', 'เป็นเส้นทางเดินป่าระยะสั้นที่สุด และสภาพทางเดินสะดวกที่สุด เหมาะกับนักท่องเที่ยวทุกเพศทุกวัย เส้นทางจะลัดเลาะในป่าดิบชื้นสลับกับป่าดิบแล้งที่มีความอุดมสมบูรณ์ ระหว่างเส้นทางจะได้พบกับไม้กฤษณาหรือไม้หอม ซึ่งเป็นไม้ที่มีคุณค่า มีสารที่ให้กลิ่นหอมจรุงใจเมื่อโดนไฟเผา และอาจได้พบกับสัตว์ป่า เช่น ชะนีมือขาว ชะนีมงกุฎ และนกชนิดต่างๆ ด้วย ปลายเส้นทางจะพบกับน้ำตกกองแก้ว ที่ให้สัมผัสถึงความชุ่มฉ่ำเย็นของสายน้ำในป่าดิบ ซึ่งเกิดจากหินภูเขาไฟ และป่าพรุน้ำจืดที่เหมาะแก่การถ่ายภาพและศึกษาระบบนิเวศ', 'ง่าย', 1.2, '45 นาที - 1 ชั่วโมง'),
  ('อุทยานแห่งชาติภูกระดึง', 'เส้นทางศึกษาธรรมชาติหล่มสัก', 'เป็นเส้นทางเดินชมวิวเลียบหน้าผา ระยะทางประมาณ 9 กิโลเมตรจากศูนย์บริการนักท่องเที่ยววังกวาง ใช้เวลาเดินเท้าประมาณ 3-4 ชั่วโมง เป็นจุดชมพระอาทิตย์ตกดินยอดฮิตที่มีแผ่นหินยื่นออกไปและมีต้นสนเป็นฉากหลัง', 'ปานกลาง', 9.5, '4.5 ชั่วโมง'),
  ('อุทยานแห่งชาติภูกระดึง', 'เส้นทางศึกษาธรรมชาติผานกแอ่น - น้ำตกถ้ำใหญ่', 'เป็นเส้นทางที่ใหญ่ที่สุดบนยอดภูกระดึง โดยเริ่มที่ศูนย์บริการนักท่องเที่ยวไปผานกแอ่นวนกลับที่ศูนย์บริการและไปน้ำตกถ้ำใหญ่', 'ปานกลาง', 10.5, '6 ชั่วโมง'),
  ('อุทยานแห่งชาติดอยอินทนนท์', 'เส้นทางศึกษาธรรมชาติกิ่วแม่ปาน', 'เป็นเส้นทางเดินศึกษาธรรมชาติระยะสั้นแบบวงรอบ ระยะทางประมาณ 3.2 กิโลเมตร ใช้เวลาเดิน 2-3 ชั่วโมง ไฮไลท์สำคัญคือจุดชมวิวทะเลหมอก จุดชมกุหลาบพันปี และทุ่งหญ้ากึ่งอัลไพน์', 'ง่าย', 2.8, '2.5 ชั่วโมง'),
  ('อุทยานแห่งชาติดอยอินทนนท์', 'เส้นทางศึกษาธรรมชาติอ่างกา', 'ตั้งอยู่บนยอดดอยอินทนนท์ จังหวัดเชียงใหม่ ฝั่งตรงข้ามป้ายสูงสุดแดนสยาม เป็นเส้นทางศึกษาธรรมชาติระยะสั้นประมาณ 320 - 360 เมตร ใช้เวลาเดินสบายๆ ราว 30 นาที บนสะพานไม้ตลอดสาย พาชมความอุดมสมบูรณ์ของป่าดึกดำบรรพ์ และป่าพรุภูเขาที่สูงที่สุดในประเทศไทย', 'ง่าย', 0.36, '30 นาที'),
  ('อุทยานแห่งชาติแก่งกระจาน', 'เส้นทางศึกษาธรรมชาติน้ำตกป่าละอู', 'หนึ่งในเสน่ห์หลักของน้ำตกป่าละอูที่ทำให้ที่นี่ต่างจากน้ำตกทั่วไปคือเส้นทางเดินที่ต้องลัดเลาะผ่านธรรมชาติจริงๆ ไม่มีบันไดปูนแต่เป็นทางเท้าที่ไต่ระดับขึ้นไปตามลำธาร ข้ามโขดหิน เดินเลียบขอบน้ำ บางช่วงต้องก้าวข้ามหินเปียกหรือเกาะรากไม้ขึ้นเนิน', 'ง่าย', 2, '1 ชั่วโมง'),
  ('อุทยานแห่งชาติแก่งกระจาน', 'เส้นทางศึกษาธรรมชาติเฉลิมพระเกียรติฯกล้วยไม้พะเนินทุ่ง', 'เป็นเส้นทางเดินป่าลึก ที่ถูกจัดทำขึ้นเพื่อสื่อความหมายและให้ความรู้เรื่องความหลากหลายทางชีวภาพ โดยเฉพาะการเป็นแหล่งรวบรวม "กล้วยไม้ป่าหายาก" นานาชนิดที่เกาะอยู่ตามคบไม้ใหญ่ในป่าดิบชื้น', 'ง่าย', 0.665, '30 นาที'),
  ('อุทยานแห่งชาติเขาสก', 'เส้นทางศึกษาธรรมชาติถ้ำน้ำทะลุ', 'ไฮไลต์คือการเดินป่าและลุยน้ำในลำธารลอดถ้ำระยะทาง ๕๐๐ เมตร ชมหินงอกหินย้อย ใช้เวลาไป-กลับราว ๓-๔ ชั่วโมง', 'ปานกลาง', 3, '4 ชั่วโมง'),
  ('อุทยานแห่งชาติเขาสก', 'เส้นทางศึกษาธรรมชาติสันยางร้อย', 'ป็นเส้นทางเดินป่าดิบชื้นระยะสั้นที่ได้รับ การรับรองมาตรฐานคุณภาพแหล่งท่องเที่ยวทางธรรมชาติ จากกรมการท่องเที่ยว ทางเดินจะเริ่มต้นจากบริเวณด้านหลังศูนย์บริการนักท่องเที่ยวของอุทยานฯ เป็นเส้นทางที่เหมาะมากสำหรับนักท่องเที่ยวที่ต้องการเดินชมความสมบูรณ์ของป่าฝนเขตร้อนแบบไม่ต้องลุยหนักจนเกินไป', 'ง่าย', 2, '1 ชั่วโมง'),
  ('อุทยานแห่งชาติหมู่เกาะสิมิลัน', 'เส้นทางศึกษาธรรมชาติหินเรือใบ', 'เส้นทางนี้เป็นทางเดินสั้นๆ แต่ลาดชัน ท้าทายแรงขา เพื่อพานักท่องเที่ยวไต่ขึ้นสู่ยอดเขาหินแกรนิตอันเป็นสัญลักษณ์ระดับโลกของทะเลไทย', 'ง่าย', 0.34, '30 นาที'),
  ('อุทยานแห่งชาติหมู่เกาะสิมิลัน', 'เส้นทางศึกษาธรรมชาติสิมิลันเฉลิมพระเกียรติ', 'เป็นเส้นทางเดินระยะสั้น ที่สามารถไปหาดเล็กและจุดชมวิว', 'ง่าย', 0.77, '45 นาที'),
  ('อุทยานแห่งชาติเขาแหลมหญ้า-หมู่เกาะเสม็ด', 'เส้นทางศึกษาธรรมชาติอุทยานแห่งชาติเขาแหลมหญ้า-หมู่เกาะเสม็ด', 'เป็นเส้นทางเดินระยะสั้น เป็นเส้นทางเดินเลียบชายฝั่งทะเลที่สวยงามและได้รับความนิยม ที่สามารถไปยังจุดชมวิวได้ และวนกลับมาจุดเริ่มต้นได้โดยจะผ่านอุโมงค์ป่าที่ร่มรื่น', 'ง่าย', 1.1, '1 ชั่วโมง'),
  ('อุทยานแห่งชาติดอยผ้าห่มปก', 'เส้นทางศึกษาธรรมชาติน้ำพุร้อน', 'เป็นเส้นทางที่จะนำไปบ่อน้ำพุร้อนที่ตัดผ่านป่าเบญจพรรณอันร่มรื่นมาสิ้นสุดที่บริเวณบ่อน้ำพุร้อน เหมาะสำหรับนักท่องเที่ยวทุกเพศทุกวัยที่ต้องการเดินออกกำลังกายเบา ๆ ชมธรรมชาติ และเรียนรู้เรื่องพลังงานความร้อนใต้พิภพ', 'ง่าย', 0.38, '30 นาที'),
  ('อุทยานแห่งชาติดอยผ้าห่มปก', 'เส้นทางศึกษาธรรมชาติดอยผ้าห่มปก', 'เป็นเส้นทางเดินป่าเพื่อขึ้นสู่ยอดดอยที่สูงเป็นอันดับ 2 ของประเทศไทย (ความสูง 2,285 เมตร จากระดับน้ำทะเลปานกลาง)', 'ปานกลาง', 3.5, '3 ชั่วโมง'),
  ('อุทยานแห่งชาติเอราวัณ', 'เส้นทางศึกษาธรรมชาติอุทยานแห่งชาติเอราวัณ', 'เส้นทางจะตัดผ่านป่าเบญจพรรณ ป่าดิบแล้ง และป่าไผ่ไว้ทั้งหมด 3 เส้นทางหลัก เพื่อให้นักท่องเที่ยวได้เดินชมพืชพรรณ ป่าไม้หินปูน และระบบนิเวศอันอุดมสมบูรณ์ โดยแต่ละเส้นทางมีความยาวและจุดเด่นที่แตกต่างกันอย่างชัดเจน', 'ง่าย', 0.8, '30 นาที'),
  ('อุทยานแห่งชาติผาแต้ม', 'เส้นทางศึกษาธรรมชาติภาพเขียนสีก่อนประวัติศาสตร์ผาแต้ม', 'อุทยานแห่งชาติผาแต้ม อำเภอโขงเจียม จังหวัดอุบลราชธานี เป็นเส้นทางเดินเท้าเลียบใต้เพิงผาหินทรายเพื่อชม แหล่งภาพเขียนสีก่อนประวัติศาสตร์ที่ยาวที่สุดในประเทศไทย มีอายุเก่าแก่ประมาณ 3,000 - 4,000 ปี โดยมีระยะทางเดินวนรอบวงกลม (Loop Trail)', 'ง่าย', 4, '2 ชั่วโมง'),
  ('อุทยานแห่งชาติผาแต้ม', 'เส้นทางศึกษาธรรมชาติผาชนะได', 'เป็นหน้าผาสูงชันริมแม่น้ำโขงที่เป็น "จุดชมพระอาทิตย์ขึ้นแห่งแรกของประเทศไทย" และเป็นพิกัดที่กรมอุตุนิยมวิทยาใช้บอกเวลาแจ้งเตือนดวงอาทิตย์ขึ้นในทุก ๆ เช้า', 'ง่าย', 7.2, '4 ชั่วโมง')
) as v(park_name_th, trail_name, description, difficulty, distance_km, duration)
join inserted_parks ip on ip.name_th = v.park_name_th;
